export function parseTodayData(): TodayRecord[] {
  return _raw.map(r => ({
    region: r[0] as string,
    manager: r[1] as string,
    city: r[2] as string,
    storeName: r[3] as string,
    operator: r[4] as string,
    tradeType: r[5] as string,
    storeRecovery: r[6] as number,
    douyinRecovery: r[7] as number,
    nonDeliveryUsers: r[8] as number,
  }));
}

// 预解析缓存
let _cache: TodayRecord[] | null = null;
export function getTodayData(): TodayRecord[] {
  if (!_cache) _cache = parseTodayData();
  return _cache;
}
